/// <summary>
/// Extension class of class AssetReportsController
/// </summary>
[ExtensionOf(classStr(AssetReportsController))]
internal final class ETGAssetReportsController_Extension
{
}

Method.Source:
/// <summary>
/// This method overrides method preRunModifyContract to call report ReportWithNAV0
/// when ETGAssetsWithNBV0 is YES
/// </summary>
protected void preRunModifyContract()
{
    next preRunModifyContract();
    AssetBalancesContract contract;

    contract = this.parmReportContract().parmRdpContract() as AssetBalancesContract;
    if(contract.parmETGAssetsNAV() == NoYes::Yes)
    {
        this.parmReportContract().parmReportName(ssrsReportStr(ETGAssetBalances, ReportWithNAV0));
    }
}
